class ExpressedConsent(InformedConsent, LegalBasis):
    """
    Consent that is expressed through an action intended to convey a
    consenting decision
    """
    linkml_meta: ClassVar[LinkMLMeta] = LinkMLMeta({'aliases': ['Expressed Consent'],
         'annotations': {'skos_in_scheme': {'tag': 'skos_in_scheme',
                                            'value': 'consent-types-classes'}},
         'class_uri': 'dpv:ExpressedConsent',
         'comments': ['Expressed consent requires the individual take a specific and\n'
                      'unambiguous action that directly indicates their consent. This '
                      'action\n'
                      'may be a part of other processes such as setting preferences, '
                      'or\n'
                      'agreeing to a contract, or other matters not relating to '
                      'consent. An\n'
                      'example of expressed consent is interacting with a checkbox '
                      'within a\n'
                      'dashboard or clicking a button on a web form'],
         'exact_mappings': ['dpv_upstream:ExpressedConsent',
                            'dpv_owl:ExpressedConsent'],
         'from_schema': 'https://w3id.org/lmodel/dpv/core',
         'in_subset': ['consent_types_subset', 'core_subset'],
         'mixins': ['LegalBasis']})

    id: str = Field(default=..., description="""Stable identifier for the instance. Typically a CURIE or IRI naming the
RDF subject this LinkML instance corresponds to.""", json_schema_extra = { "linkml_meta": {'domain_of': ['DpvThing'], 'in_subset': ['core_subset']} })


class ExplicitlyExpressedConsent(ExpressedConsent, LegalBasis):
    """
    Consent that is expressed through an explicit action solely conveying a
    consenting decision
    """
    linkml_meta: ClassVar[LinkMLMeta] = LinkMLMeta({'aliases': ['Explicitly Expressed Consent'],
         'annotations': {'skos_in_scheme': {'tag': 'skos_in_scheme',
                                            'value': 'consent-types-classes'}},
         'class_uri': 'dpv:ExplicitlyExpressedConsent',
         'comments': ['Explicitly expressed consent is a more specific form of '
                      'Expressed\n'
                      "consent where the action taken must 'explicitly' relate to only "
                      'the\n'
                      'consent decision. Expressed consent where the consenting is '
                      'part of\n'
                      'other matters therefore cannot satisfy the requirements of '
                      'explicitly\n'
                      'expressed consent. An example of explicit action expressing '
                      'the\n'
                      'consenting decision is a button on a web form where the form '
                      'only\n'
                      'relates to consent, or it is accompanied with suitable text '
                      'that\n'
                      'reiterates what the consenting decision is about'],
         'exact_mappings': ['dpv_upstream:ExplicitlyExpressedConsent',
                            'dpv_owl:ExplicitlyExpressedConsent'],
         'from_schema': 'https://w3id.org/lmodel/dpv/core',
         'in_subset': ['consent_types_subset', 'core_subset'],
         'mixins': ['LegalBasis']})

    id: str = Field(default=..., description="""Stable identifier for the instance. Typically a CURIE or IRI naming the
RDF subject this LinkML instance corresponds to.""", json_schema_extra = { "linkml_meta": {'domain_of': ['DpvThing'], 'in_subset': ['core_subset']} })


