class Tracking(Use, Processing):
    """
    to use data to track a specific factor (e.g. a human or their
    activities) across multiple distinct contexts
    """
    linkml_meta: ClassVar[LinkMLMeta] = LinkMLMeta({'aliases': ['Tracking'],
         'annotations': {'skos_in_scheme': {'tag': 'skos_in_scheme',
                                            'value': 'processing-classes'}},
         'class_uri': 'dpv:Tracking',
         'comments': ['Tracking is a widely used (and abused) concept and therefore '
                      'carries\n'
                      'several distinct interpretations, for example see Do Not Track '
                      'which\n'
                      'defines tracking in the context of the web, and where other '
                      'forms of\n'
                      'tracking such as location tracking or physical biometric '
                      'tracking may\n'
                      'exist which are defined differently. For this concept, DPVCG '
                      'defines\n'
                      'Tracking in the broadest possible sense and strongly recommends '
                      'adopters\n'
                      'to provide their specific definition or interpretation by '
                      'either\n'
                      'extending this concept, through a usage note, or by '
                      'contributing the\n'
                      'specific term back to DPVCG for inclusion in DPV or an '
                      'extension. This\n'
                      'concept may change in the future based on developments in '
                      'privacy and\n'
                      'legal spaces. In DPV, Tracking is defined as a type of '
                      'processing\n'
                      'operation that may collect and/or may use data - which covers '
                      'both\n'
                      'initial collection and usage as well as subsequent use of '
                      'existing data\n'
                      'to track an individual. The classification of Tracking as a '
                      'processing\n'
                      'operation also implies that it is not sufficient as a Purpose '
                      'on its own\n'
                      'and therefore a suitable purpose from the DPV taxonomy should '
                      'be used to\n'
                      'justify it.'],
         'exact_mappings': ['dpv_upstream:Tracking', 'dpv_owl:Tracking'],
         'from_schema': 'https://w3id.org/lmodel/dpv/core',
         'in_subset': ['processing_subset', 'core_subset'],
         'mixins': ['Processing']})

    id: str = Field(default=..., description="""Stable identifier for the instance. Typically a CURIE or IRI naming the
RDF subject this LinkML instance corresponds to.""", json_schema_extra = { "linkml_meta": {'domain_of': ['DpvThing'], 'in_subset': ['core_subset']} })


